create table dirkspzm32.isi_event_cfg (
    sid                varchar2(2 char) not null enable,
    firma_nr           number(6, 0) not null enable,
    event_cfg_id       number(*, 0) not null enable,
    event_handler      varchar2(50 char) not null enable,
    name               varchar2(100 char) not null enable,
    caption            varchar2(100 char) not null enable,
    beschreibung       varchar2(255 char),
    event_type         varchar2(50 char) not null enable,
    event_function     varchar2(50 char) not null enable,
    object_types       varchar2(255 char) not null enable,
    object_names       varchar2(255 char) not null enable,
    operators          varchar2(50 char) not null enable,
    abort_types        varchar2(100 char) not null enable,
    msg_text_src       varchar2(50 char),
    msg_text_id_true   number(*, 5),
    msg_text_id_false  number(*, 5),
    open_dlg_unique_id varchar2(100 char),
    object_captions    varchar2(255 char)
);

alter table dirkspzm32.isi_event_cfg
    add constraint pk_isi_event_cfg
        primary key ( sid,
                      firma_nr,
                      event_cfg_id )
            using index enable;


